router.post('/vulnerable/calculate', (req, res) => {
  const { formula } = req.body;
  try {
    // ⚠ eval() runs ANY JavaScript, not just math
    const result = eval(formula);
    res.json({ result: String(result) });
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
});

